import { APIGatewayProxyEvent } from 'aws-lambda';

// Mock dependencies
const mockBuildAuthorizationUrl = jest.fn();
const mockExchangeCodeForTokens = jest.fn();
const mockVerifyIdToken = jest.fn();
const mockFindOrCreateUser = jest.fn();
const mockGenerateTokens = jest.fn();

jest.mock('../src/tara-client', () => ({
  createTaraClient: jest.fn().mockResolvedValue({
    buildAuthorizationUrl: (...args: unknown[]) => mockBuildAuthorizationUrl(...args),
    exchangeCodeForTokens: (...args: unknown[]) => mockExchangeCodeForTokens(...args),
    verifyIdToken: (...args: unknown[]) => mockVerifyIdToken(...args),
  }),
}));

jest.mock('../src/cognito-client', () => ({
  createCognitoClient: jest.fn().mockReturnValue({
    findOrCreateUser: (...args: unknown[]) => mockFindOrCreateUser(...args),
    generateTokens: (...args: unknown[]) => mockGenerateTokens(...args),
  }),
}));

import { callbackHandler, startHandler } from '../src/handler';

/**
 * Mutation-killing tests for handler.ts
 * Targets: string literals, conditional expressions, cookie values, redirect URLs,
 * arithmetic operators, block statements
 */
describe('handler.ts mutation kills', () => {
  const originalEnv = process.env;

  beforeEach(() => {
    jest.clearAllMocks();
    process.env = { ...originalEnv };
    process.env.STAGE = 'dev';
    process.env.FRONTEND_URL_DEV = 'https://hak-dev.askend-lab.com';
    process.env.FRONTEND_URL_PROD = 'https://hak.askend-lab.com';
  });

  afterAll(() => {
    process.env = originalEnv;
  });

  const makeEvent = (overrides: Partial<APIGatewayProxyEvent> = {}): APIGatewayProxyEvent => ({
    httpMethod: 'GET',
    path: '/auth/tara/callback',
    queryStringParameters: null,
    headers: {},
    body: null,
    isBase64Encoded: false,
    pathParameters: null,
    stageVariables: null,
    requestContext: {} as unknown as APIGatewayProxyEvent['requestContext'],
    resource: '',
    multiValueHeaders: {},
    multiValueQueryStringParameters: null,
    ...overrides,
  });

  const makeStateCookie = (state: Record<string, unknown>): string => {
    return Buffer.from(JSON.stringify(state)).toString('base64url');
  };

  // --- getFrontendUrl mutations ---

  describe('getFrontendUrl', () => {
    it('should use prod URL when STAGE=prod', async () => {
      process.env.STAGE = 'prod';
      mockBuildAuthorizationUrl.mockReturnValue('https://tara.ee/auth');

      const result = await startHandler(makeEvent());
      // startHandler creates state with redirectUri = getFrontendUrl()
      // The cookie contains the state with redirectUri
      const cookie = result.headers?.['Set-Cookie'] as string;
      const encoded = cookie.split('=')[1].split(';')[0];
      const state = JSON.parse(Buffer.from(encoded, 'base64url').toString());
      expect(state.redirectUri).toBe('https://hak.askend-lab.com');
    });

    it('should use dev URL when STAGE=dev', async () => {
      process.env.STAGE = 'dev';
      mockBuildAuthorizationUrl.mockReturnValue('https://tara.ee/auth');

      const result = await startHandler(makeEvent());
      const cookie = result.headers?.['Set-Cookie'] as string;
      const encoded = cookie.split('=')[1].split(';')[0];
      const state = JSON.parse(Buffer.from(encoded, 'base64url').toString());
      expect(state.redirectUri).toBe('https://hak-dev.askend-lab.com');
    });

    it('should default to dev when STAGE is not set', async () => {
      delete process.env.STAGE;
      mockBuildAuthorizationUrl.mockReturnValue('https://tara.ee/auth');

      const result = await startHandler(makeEvent());
      const cookie = result.headers?.['Set-Cookie'] as string;
      const encoded = cookie.split('=')[1].split(';')[0];
      const state = JSON.parse(Buffer.from(encoded, 'base64url').toString());
      expect(state.redirectUri).toBe('https://hak-dev.askend-lab.com');
    });
  });

  // --- startHandler mutations ---

  describe('startHandler mutations', () => {
    it('should return 302 status code', async () => {
      mockBuildAuthorizationUrl.mockReturnValue('https://tara.ee/auth');
      const result = await startHandler(makeEvent());
      expect(result.statusCode).toBe(302);
    });

    it('should set Location header to auth URL', async () => {
      mockBuildAuthorizationUrl.mockReturnValue('https://tara.ee/oidc/authorize?x=1');
      const result = await startHandler(makeEvent());
      expect(result.headers?.Location).toBe('https://tara.ee/oidc/authorize?x=1');
    });

    it('should set Cache-Control to no-store', async () => {
      mockBuildAuthorizationUrl.mockReturnValue('https://tara.ee/auth');
      const result = await startHandler(makeEvent());
      expect(result.headers?.['Cache-Control']).toBe('no-store');
    });

    it('should set HttpOnly Secure SameSite=Lax cookie', async () => {
      mockBuildAuthorizationUrl.mockReturnValue('https://tara.ee/auth');
      const result = await startHandler(makeEvent());
      const cookie = result.headers?.['Set-Cookie'] as string;
      expect(cookie).toContain('HttpOnly');
      expect(cookie).toContain('Secure');
      expect(cookie).toContain('SameSite=Lax');
      expect(cookie).toContain('Max-Age=600');
      expect(cookie).toContain('Path=/');
    });

    it('should have empty body', async () => {
      mockBuildAuthorizationUrl.mockReturnValue('https://tara.ee/auth');
      const result = await startHandler(makeEvent());
      expect(result.body).toBe('');
    });

    it('should pass state and nonce to buildAuthorizationUrl', async () => {
      mockBuildAuthorizationUrl.mockReturnValue('https://tara.ee/auth');
      await startHandler(makeEvent());
      expect(mockBuildAuthorizationUrl).toHaveBeenCalledWith(
        expect.any(String),
        expect.any(String)
      );
      const [state, nonce] = mockBuildAuthorizationUrl.mock.calls[0];
      expect(state.length).toBeGreaterThan(10);
      expect(nonce.length).toBeGreaterThan(10);
      expect(state).not.toBe(nonce);
    });

    it('should include state and nonce in cookie', async () => {
      mockBuildAuthorizationUrl.mockReturnValue('https://tara.ee/auth');
      const result = await startHandler(makeEvent());
      const cookie = result.headers?.['Set-Cookie'] as string;
      const encoded = cookie.split('=')[1].split(';')[0];
      const stateObj = JSON.parse(Buffer.from(encoded, 'base64url').toString());
      expect(stateObj.state).toBeTruthy();
      expect(stateObj.nonce).toBeTruthy();
      expect(stateObj.createdAt).toBeTruthy();
      expect(stateObj.redirectUri).toBeTruthy();
    });
  });

  // --- parseStateCookie mutations ---

  describe('parseStateCookie mutations', () => {
    it('should handle cookie header with no tara_auth_state', async () => {
      const event = makeEvent({
        queryStringParameters: { code: 'c', state: 's' },
        headers: { Cookie: 'other_cookie=val' },
      });
      const result = await callbackHandler(event);
      expect(result.statusCode).toBe(302);
      expect(result.headers?.Location).toContain('error=Invalid+session');
    });

    it('should handle cookie header with semicolons correctly', async () => {
      const validState = { state: 'test-s', nonce: 'n', redirectUri: 'https://hak-dev.askend-lab.com', createdAt: Date.now() };
      const encoded = makeStateCookie(validState);
      const event = makeEvent({
        queryStringParameters: { code: 'c', state: 'test-s' },
        headers: { Cookie: `other=x; tara_auth_state=${encoded}; another=y` },
      });
      mockExchangeCodeForTokens.mockResolvedValue({ id_token: 'id', access_token: 'at' });
      mockVerifyIdToken.mockResolvedValue({ sub: 'EE123', nonce: 'n' });
      mockFindOrCreateUser.mockResolvedValue('u@e.com');
      mockGenerateTokens.mockResolvedValue({ accessToken: 'a', idToken: 'i', refreshToken: 'r', expiresIn: 3600 });

      const result = await callbackHandler(event);
      expect(result.statusCode).toBe(302);
      expect(result.headers?.Location).not.toContain('error=');
    });
  });

  // --- callbackHandler error paths ---

  describe('callbackHandler error message mutations', () => {
    it('should include specific error_description from TARA', async () => {
      const event = makeEvent({
        queryStringParameters: { error: 'access_denied', error_description: 'User cancelled auth' },
      });
      const result = await callbackHandler(event);
      expect(result.headers?.Location).toContain('error=User+cancelled+auth');
    });

    it('should fall back to error code when no error_description', async () => {
      const event = makeEvent({
        queryStringParameters: { error: 'server_error' },
      });
      const result = await callbackHandler(event);
      expect(result.headers?.Location).toContain('error=server_error');
    });

    it('should include "Missing code or state" error text', async () => {
      const validState = { state: 's', nonce: 'n', redirectUri: 'https://hak-dev.askend-lab.com', createdAt: Date.now() };
      const event = makeEvent({
        queryStringParameters: { state: 's' },
        headers: { Cookie: `tara_auth_state=${makeStateCookie(validState)}` },
      });
      const result = await callbackHandler(event);
      expect(result.headers?.Location).toContain('Missing+code+or+state');
    });

    it('should include "State mismatch" error text', async () => {
      const validState = { state: 'correct', nonce: 'n', redirectUri: 'https://hak-dev.askend-lab.com', createdAt: Date.now() };
      const event = makeEvent({
        queryStringParameters: { code: 'c', state: 'wrong' },
        headers: { Cookie: `tara_auth_state=${makeStateCookie(validState)}` },
      });
      const result = await callbackHandler(event);
      expect(result.headers?.Location).toContain('State+mismatch');
    });

    it('should include "Session expired" error text with > operator', async () => {
      const expiredState = { state: 's', nonce: 'n', redirectUri: 'https://hak-dev.askend-lab.com', createdAt: Date.now() - 11 * 60 * 1000 };
      const event = makeEvent({
        queryStringParameters: { code: 'c', state: 's' },
        headers: { Cookie: `tara_auth_state=${makeStateCookie(expiredState)}` },
      });
      const result = await callbackHandler(event);
      expect(result.headers?.Location).toContain('Session+expired');
    });

    it('should NOT expire session at exactly 10 minutes', async () => {
      const borderState = { state: 's', nonce: 'n', redirectUri: 'https://hak-dev.askend-lab.com', createdAt: Date.now() - 10 * 60 * 1000 + 100 };
      const event = makeEvent({
        queryStringParameters: { code: 'c', state: 's' },
        headers: { Cookie: `tara_auth_state=${makeStateCookie(borderState)}` },
      });
      mockExchangeCodeForTokens.mockResolvedValue({ id_token: 'id', access_token: 'at' });
      mockVerifyIdToken.mockResolvedValue({ sub: 'EE123', nonce: 'n' });
      mockFindOrCreateUser.mockResolvedValue('u@e.com');
      mockGenerateTokens.mockResolvedValue({ accessToken: 'a', idToken: 'i', refreshToken: 'r', expiresIn: 3600 });

      const result = await callbackHandler(event);
      expect(result.headers?.Location).not.toContain('error=');
    });

    it('should include "Authentication failed" on catch error', async () => {
      const validState = { state: 's', nonce: 'n', redirectUri: 'https://hak-dev.askend-lab.com', createdAt: Date.now() };
      const event = makeEvent({
        queryStringParameters: { code: 'c', state: 's' },
        headers: { Cookie: `tara_auth_state=${makeStateCookie(validState)}` },
      });
      mockExchangeCodeForTokens.mockRejectedValue(new Error('fail'));
      const result = await callbackHandler(event);
      expect(result.headers?.Location).toContain('Authentication+failed');
    });

    it('should clear state cookie on catch error', async () => {
      const validState = { state: 's', nonce: 'n', redirectUri: 'https://hak-dev.askend-lab.com', createdAt: Date.now() };
      const event = makeEvent({
        queryStringParameters: { code: 'c', state: 's' },
        headers: { Cookie: `tara_auth_state=${makeStateCookie(validState)}` },
      });
      mockExchangeCodeForTokens.mockRejectedValue(new Error('fail'));
      const result = await callbackHandler(event);
      expect(result.headers?.['Set-Cookie']).toContain('Max-Age=0');
    });
  });

  // --- redirectToFrontend mutations ---

  describe('redirectToFrontend mutations', () => {
    it('should redirect to /auth/callback path', async () => {
      const validState = { state: 's', nonce: 'n', redirectUri: 'https://hak-dev.askend-lab.com', createdAt: Date.now() };
      const event = makeEvent({
        queryStringParameters: { error: 'test_error' },
        headers: { Cookie: `tara_auth_state=${makeStateCookie(validState)}` },
      });
      const result = await callbackHandler(event);
      const location = result.headers?.Location as string;
      expect(location).toContain('/auth/callback');
      expect(location).toContain('error=test_error');
    });

    it('should include Set-Cookie when provided', async () => {
      const validState = { state: 's', nonce: 'n', redirectUri: 'https://hak-dev.askend-lab.com', createdAt: Date.now() };
      const event = makeEvent({
        queryStringParameters: { code: 'c', state: 's' },
        headers: { Cookie: `tara_auth_state=${makeStateCookie(validState)}` },
      });
      mockExchangeCodeForTokens.mockRejectedValue(new Error('fail'));
      const result = await callbackHandler(event);
      // Should have Set-Cookie with clear cookie (Max-Age=0)
      expect(result.headers?.['Set-Cookie']).toBeDefined();
    });

    it('should NOT include Set-Cookie for non-catch error redirects', async () => {
      const event = makeEvent({
        queryStringParameters: { error: 'access_denied' },
      });
      const result = await callbackHandler(event);
      expect(result.headers?.['Set-Cookie']).toBeUndefined();
    });
  });

  // --- redirectToFrontendWithCookies mutations ---

  describe('redirectToFrontendWithCookies mutations', () => {
    const setupSuccessFlow = () => {
      const validState = { state: 's', nonce: 'n', redirectUri: 'https://hak-dev.askend-lab.com', createdAt: Date.now() };
      mockExchangeCodeForTokens.mockResolvedValue({ id_token: 'id', access_token: 'at' });
      mockVerifyIdToken.mockResolvedValue({ sub: 'EE123', nonce: 'n' });
      mockFindOrCreateUser.mockResolvedValue('u@e.com');
      mockGenerateTokens.mockResolvedValue({ accessToken: 'acc-tok', idToken: 'id-tok', refreshToken: 'ref-tok', expiresIn: 7200 });
      return makeEvent({
        queryStringParameters: { code: 'c', state: 's' },
        headers: { Cookie: `tara_auth_state=${makeStateCookie(validState)}` },
      });
    };

    it('should set access_token cookie with correct value and max-age', async () => {
      const event = setupSuccessFlow();
      const result = await callbackHandler(event);
      const cookies = result.multiValueHeaders?.['Set-Cookie'] as string[];
      const accessCookie = cookies.find(c => c.startsWith('access_token='));
      expect(accessCookie).toContain('access_token=acc-tok');
      expect(accessCookie).toContain('Max-Age=7200');
      expect(accessCookie).toContain('SameSite=Strict');
    });

    it('should set id_token cookie with correct value', async () => {
      const event = setupSuccessFlow();
      const result = await callbackHandler(event);
      const cookies = result.multiValueHeaders?.['Set-Cookie'] as string[];
      const idCookie = cookies.find(c => c.startsWith('id_token='));
      expect(idCookie).toContain('id_token=id-tok');
      expect(idCookie).toContain('Max-Age=7200');
    });

    it('should set refresh_token cookie with 30-day max-age', async () => {
      const event = setupSuccessFlow();
      const result = await callbackHandler(event);
      const cookies = result.multiValueHeaders?.['Set-Cookie'] as string[];
      const refreshCookie = cookies.find(c => c.startsWith('refresh_token='));
      expect(refreshCookie).toContain('refresh_token=ref-tok');
      // 30 * 24 * 60 * 60 = 2592000
      expect(refreshCookie).toContain('Max-Age=2592000');
    });

    it('should set is_authenticated=true (not HttpOnly)', async () => {
      const event = setupSuccessFlow();
      const result = await callbackHandler(event);
      const cookies = result.multiValueHeaders?.['Set-Cookie'] as string[];
      const authCookie = cookies.find(c => c.startsWith('is_authenticated='));
      expect(authCookie).toContain('is_authenticated=true');
      expect(authCookie).not.toContain('HttpOnly');
      expect(authCookie).toContain('Secure');
      expect(authCookie).toContain('SameSite=Strict');
    });

    it('should clear state cookie in success cookies', async () => {
      const event = setupSuccessFlow();
      const result = await callbackHandler(event);
      const cookies = result.multiValueHeaders?.['Set-Cookie'] as string[];
      const clearCookie = cookies.find(c => c.includes('tara_auth_state='));
      expect(clearCookie).toContain('Max-Age=0');
    });

    it('should have 5 cookies total', async () => {
      const event = setupSuccessFlow();
      const result = await callbackHandler(event);
      const cookies = result.multiValueHeaders?.['Set-Cookie'] as string[];
      expect(cookies).toHaveLength(5);
    });

    it('should set no-store cache control', async () => {
      const event = setupSuccessFlow();
      const result = await callbackHandler(event);
      expect(result.headers?.['Cache-Control']).toBe('no-store');
    });

    it('should redirect to /auth/callback', async () => {
      const event = setupSuccessFlow();
      const result = await callbackHandler(event);
      expect(result.headers?.Location).toBe('https://hak-dev.askend-lab.com/auth/callback');
    });
  });

  // --- STATE_TTL_MS arithmetic mutation ---

  describe('STATE_TTL_MS value', () => {
    it('session at 9 minutes should be valid', async () => {
      const state = { state: 's', nonce: 'n', redirectUri: 'https://hak-dev.askend-lab.com', createdAt: Date.now() - 9 * 60 * 1000 };
      const event = makeEvent({
        queryStringParameters: { code: 'c', state: 's' },
        headers: { Cookie: `tara_auth_state=${makeStateCookie(state)}` },
      });
      mockExchangeCodeForTokens.mockResolvedValue({ id_token: 'id', access_token: 'at' });
      mockVerifyIdToken.mockResolvedValue({ sub: 'EE123', nonce: 'n' });
      mockFindOrCreateUser.mockResolvedValue('u@e.com');
      mockGenerateTokens.mockResolvedValue({ accessToken: 'a', idToken: 'i', refreshToken: 'r', expiresIn: 3600 });

      const result = await callbackHandler(event);
      expect(result.headers?.Location).not.toContain('error=');
    });

    it('session at 11 minutes should be expired', async () => {
      const state = { state: 's', nonce: 'n', redirectUri: 'https://hak-dev.askend-lab.com', createdAt: Date.now() - 11 * 60 * 1000 };
      const event = makeEvent({
        queryStringParameters: { code: 'c', state: 's' },
        headers: { Cookie: `tara_auth_state=${makeStateCookie(state)}` },
      });
      const result = await callbackHandler(event);
      expect(result.headers?.Location).toContain('Session+expired');
    });

    it('session at exactly 10 minutes (> boundary) should still be valid', async () => {
      // Mock Date.now to eliminate timing variance
      const NOW = 1700000000000;
      const realDateNow = Date.now;
      Date.now = jest.fn().mockReturnValue(NOW);

      const TTL = 10 * 60 * 1000; // 600000ms
      // createdAt = NOW - TTL → difference is exactly TTL → (> TTL) is false → NOT expired
      const state = { state: 's', nonce: 'n', redirectUri: 'https://hak-dev.askend-lab.com', createdAt: NOW - TTL };
      const event = makeEvent({
        queryStringParameters: { code: 'c', state: 's' },
        headers: { Cookie: `tara_auth_state=${makeStateCookie(state)}` },
      });
      mockExchangeCodeForTokens.mockResolvedValue({ id_token: 'id', access_token: 'at' });
      mockVerifyIdToken.mockResolvedValue({ sub: 'EE123', nonce: 'n' });
      mockFindOrCreateUser.mockResolvedValue('u@e.com');
      mockGenerateTokens.mockResolvedValue({ accessToken: 'a', idToken: 'i', refreshToken: 'r', expiresIn: 3600 });

      const result = await callbackHandler(event);
      expect(result.headers?.Location).not.toContain('error=');

      Date.now = realDateNow;
    });

    it('session at 10min + 1ms should be expired', async () => {
      const NOW = 1700000000000;
      const realDateNow = Date.now;
      Date.now = jest.fn().mockReturnValue(NOW);

      const TTL = 10 * 60 * 1000;
      const state = { state: 's', nonce: 'n', redirectUri: 'https://hak-dev.askend-lab.com', createdAt: NOW - TTL - 1 };
      const event = makeEvent({
        queryStringParameters: { code: 'c', state: 's' },
        headers: { Cookie: `tara_auth_state=${makeStateCookie(state)}` },
      });
      const result = await callbackHandler(event);
      expect(result.headers?.Location).toContain('Session+expired');

      Date.now = realDateNow;
    });
  });

  // --- callbackHandler reads cookie from both Cookie and cookie headers ---
  describe('cookie header case', () => {
    it('should read lowercase cookie header', async () => {
      const validState = { state: 's', nonce: 'n', redirectUri: 'https://hak-dev.askend-lab.com', createdAt: Date.now() };
      const event = makeEvent({
        queryStringParameters: { code: 'c', state: 's' },
        headers: { cookie: `tara_auth_state=${makeStateCookie(validState)}` },
      });
      mockExchangeCodeForTokens.mockResolvedValue({ id_token: 'id', access_token: 'at' });
      mockVerifyIdToken.mockResolvedValue({ sub: 'EE123', nonce: 'n' });
      mockFindOrCreateUser.mockResolvedValue('u@e.com');
      mockGenerateTokens.mockResolvedValue({ accessToken: 'a', idToken: 'i', refreshToken: 'r', expiresIn: 3600 });

      const result = await callbackHandler(event);
      expect(result.statusCode).toBe(302);
      expect(result.headers?.Location).not.toContain('error=');
    });
  });
});

